const body = $json.body || $json;
const data = body.data || body;
const remoteJid = data.key?.remoteJid || data.remoteJid || '';
const fromMe = data.key?.fromMe || false;
const phone = remoteJid.replace('@s.whatsapp.net','').replace(/[^0-9]/g,'');
const messageText = (data.message?.conversation || data.message?.extendedTextMessage?.text || data.body || '').trim();

// Solo procesar mensajes del admin
const adminPhones = ($env['ADMIN_PHONES'] || '').split(',').map(p => p.trim().replace(/[^0-9]/g,''));
const esAdmin = adminPhones.includes(phone);

return [{ json: { phone, remoteJid, fromMe, messageText, esAdmin } }];

const text = $json.messageText.toUpperCase();
let comando = 'desconocido';
let parametro = '';

// Comandos disponibles:
// STATUS [SKU] — ver estado de un lead
// LISTA [estado] — listar leads por estado  
// BLOQUEAR [mes] — bloquear un mes en la agenda
// DESBLOQUEAR [mes] — desbloquear un mes
// STATS — estadísticas generales
// HELP — mostrar comandos

if (text.startsWith('STATUS')) {
  comando = 'STATUS';
  parametro = text.replace('STATUS','').trim();
} else if (text.startsWith('LISTA')) {
  comando = 'LISTA';
  parametro = text.replace('LISTA','').trim() || 'todos';
} else if (text.startsWith('BLOQUEAR')) {
  comando = 'BLOQUEAR';
  parametro = text.replace('BLOQUEAR','').trim();
} else if (text.startsWith('DESBLOQUEAR')) {
  comando = 'DESBLOQUEAR';
  parametro = text.replace('DESBLOQUEAR','').trim();
} else if (text.startsWith('STATS')) {
  comando = 'STATS';
} else if (text.startsWith('HELP') || text === '?') {
  comando = 'HELP';
}

return [{ json: { ...($input.item.json), comando, parametro } }];

const lead = $json;
if (!lead.sku) return [{ json: { respuesta: '❌ SKU no encontrado.' } }];
const msg = `📋 LEAD ${lead.sku}
Nombre: ${lead.name || 'N/A'}
Tel: ${lead.phone}
Estado: ${lead.estado}
Idioma: ${lead.language}
Email: ${lead.email || 'N/A'}
Mes: ${lead.mes_preferido || 'N/A'}
Depósito: ${lead.deposit_paid ? '✅ PAGADO (' + lead.payment_method + ')' : '⏳ Pendiente'}
Creado: ${lead.created_at ? new Date(lead.created_at).toLocaleDateString('es-CO') : 'N/A'}`;
return [{ json: { respuesta: msg, phone: $('Extraer mensaje del admin').item.json.phone } }];

const items = $input.all();
if (!items.length) return [{ json: { respuesta: '📭 No hay leads con ese estado.', phone: $('Extraer mensaje del admin').item.json.phone } }];
const lines = items.map(i => `• ${i.json.sku} | ${i.json.name || 'N/A'} | ${i.json.estado} | ${i.json.deposit_paid ? '💰' : '⏳'}`);
const msg = `📋 LEADS (${items.length}):\n` + lines.join('\n');
return [{ json: { respuesta: msg, phone: $('Extraer mensaje del admin').item.json.phone } }];

const r = $json;
const msg = r.id ? `✅ Mes bloqueado correctamente.\nID: ${r.id}\nPeriodo: ${r.fecha_inicio} → ${r.fecha_fin}` : '⚠️ No se pudo bloquear (ya existe o error).';
return [{ json: { respuesta: msg, phone: $('Extraer mensaje del admin').item.json.phone } }];

const r = $json;
const msg = r.id ? `✅ Bloqueo desactivado.\nDescripción: ${r.descripcion}` : '⚠️ No se encontró bloqueo activo para ese mes.';
return [{ json: { respuesta: msg, phone: $('Extraer mensaje del admin').item.json.phone } }];

const items = $input.all();
const byEstado = items.filter(i => i.json.estado).map(i => `  ${i.json.estado}: ${i.json.total}`).join('
');
const pagosHoy = items.find(i => i.json.pagos_hoy !== undefined)?.json?.pagos_hoy || 0;
const agendadosMes = items.find(i => i.json.agendados_mes !== undefined)?.json?.agendados_mes || 0;
const msg = `📊 ESTADÍSTICAS LUXE SMILE

Por estado:
${byEstado}

💰 Pagos hoy: ${pagosHoy}
📅 Agendados este mes: ${agendadosMes}`;
return [{ json: { respuesta: msg, phone: $('Extraer mensaje del admin').item.json.phone } }];
